const { CloudWatchLogsClient, PutLogEventsCommand } = require('@aws-sdk/client-cloudwatch-logs');

const cwLogs = new CloudWatchLogsClient();
const logGroupName = process.env.AWS_LAMBDA_LOG_GROUP_NAME;
const logStreamName = process.env.AWS_LAMBDA_LOG_STREAM_NAME;

const emfPayload = JSON.stringify({
  message: '[Embedded Metric]',
  MyMetric: 1,
  dimension1: 'value1',
  _aws: {
    Timestamp: Date.now(),
    CloudWatchMetrics: [{
      Namespace: 'MyNamespace',
      Dimensions: [['dimension1']],
      Metrics: [{ Name: 'MyMetric', Unit: 'Count' }]
    }]
  }
});

await cwLogs.send(new PutLogEventsCommand({
  logGroupName,
  logStreamName,
  logEvents: [{
    message: emfPayload,
    timestamp: Date.now()
  }]
}));
